class Solution:
    def minPages(self, pages1, pages2):
        n = len(pages1)
        res = 0
        i, j = 0, 0
        while i < n and j < n:
            if pages1[i] < pages2[j]:
                res += pages1[i]
                i += 1
            else:
                res += pages2[j]
                j += 1
        res += sum(max(x, y) for x, y in zip(pages1[i:], pages2[j:]))
        return res

solutions.cpp:
class Solution {
public:
    int minPages(std::vector<int>& pages1, std::vector<int>& pages2) {
        int n = pages1.size();
        int res = 0;
        int i = 0, j = 0;
        while (i < n && j < n) {
            if (pages1[i] < pages2[j]) {
                res += pages1[i];
                i++;
            } else {
                res += pages2[j];
                j++;
            }
        }
        res += std::accumulate(pages1.begin() + i, pages1.end(), 0, [pages2.begin() + j](int x, int y) { return std::max(x, y); });
        return res;
    }
};
